'use client'
import { useEffect,useState } from 'react'
import { supabase } from '@/lib/supabase'
import Link from 'next/link'
export default function Admin(){const[profile,setProfile]=useState<any>(null);const[users,setUsers]=useState<any[]>([]);useEffect(()=>{supabase.auth.getUser().then(async({data})=>{if(!data.user)return;const{data:p}=await supabase.from('profiles').select('*').eq('id',data.user.id).single();setProfile(p);if(p?.role==='admin'){const{data:u}=await supabase.from('profiles').select('*').order('created_at',{ascending:false});setUsers(u||[])}})},[]);if(!profile)return <main className="grid min-h-screen place-items-center">Chargement...</main>;if(profile.role!=='admin')return <main className="grid min-h-screen place-items-center"><div>Accès refusé<br/><Link href="/dashboard">Retour</Link></div></main>;return <main className="min-h-screen p-8"><h1 className="text-4xl font-semibold">Admin Aurora</h1><p className="mt-2 text-white/50">Utilisateurs inscrits</p><div className="mt-6 overflow-hidden rounded-2xl border border-white/10"><table className="w-full"><thead className="bg-white/10"><tr><th className="p-3 text-left">Email</th><th>Crédits</th><th>Rôle</th></tr></thead><tbody>{users.map(u=><tr key={u.id} className="border-t border-white/10"><td className="p-3">{u.email}</td><td className="text-center">{u.credits}</td><td className="text-center">{u.role}</td></tr>)}</tbody></table></div></main>}
